/* ============================================================
   HELPER: get total lesson count per course
   ============================================================ */

export const getTotalLessons = () => courses.reduce((s, c) => s + c.lessons.length, 0);

export const getCourseCompletionStatus = (
  courseId: string,
  completedLessons: string[],
): { completed: number; total: number; percentage: number } => {
  const course = courses.find((c) => c.id === courseId);
  if (!course) return { completed: 0, total: 0, percentage: 0 };
  const total = course.lessons.length;
  const completed = course.lessons.filter((_, i) =>
    completedLessons.includes(`${courseId}-${i}`),
  ).length;
  return { completed, total, percentage: total > 0 ? (completed / total) * 100 : 0 };
};
